// ===== CONFIGURATION - À MODIFIER =====
const NUAGE_USER   = 'votre_identifiant';
const NUAGE_PASS   = 'votre_mot_de_passe_appli';
const NUAGE_SERVER = 'nuage03.apps.education.fr';
const ALBERT_KEY   = 'sk-votre_cle_albert';
const PROF_SECRET  = 'votre_secret_prof';
// =======================================

const body = $input.first().json.body || {};
const { action } = body;
if (!action) return [{ json: { error: 'action requise' } }];

const nuageAuth = () => 'Basic ' + Buffer.from(`${NUAGE_USER}:${NUAGE_PASS}`).toString('base64');
const nuageBase = () => {
  let s = NUAGE_SERVER.replace('https://', '').replace('http://', '');
  if (s.endsWith('/')) s = s.slice(0, -1);
  return `https://${s}/remote.php/dav/files/${encodeURIComponent(NUAGE_USER)}/experia/`;
};

const hGet = (url, h={}) => fetch(url, { headers: { Authorization: nuageAuth(), ...h } });
const hPut = (url, d) => fetch(url, { method: 'PUT', headers: { Authorization: nuageAuth(), 'Content-Type': 'application/octet-stream' }, body: d });
const hMkcol = (url) => fetch(url, { method: 'MKCOL', headers: { Authorization: nuageAuth() } });
const hDel = (url) => fetch(url, { method: 'DELETE', headers: { Authorization: nuageAuth() } });

const readManifest = async () => {
  const r = await hGet(nuageBase() + 'manifest.json');
  if (r.status !== 200) return [];
  try { const p = JSON.parse(await r.text()); return Array.isArray(p) ? p : []; } catch { return []; }
};
const saveManifest = (m) => hPut(nuageBase() + 'manifest.json', JSON.stringify(m));

let res;

if (action === 'readSession') {
  const { sessionId } = body;
  if (!sessionId) { res = { success: false, error: 'sessionId requis' }; }
  else {
    const fn = (sessionId.startsWith('session_') ? sessionId : 'session_' + sessionId) + '.json';
    const r = await hGet(nuageBase() + encodeURIComponent(fn));
    if (r.status === 404) res = { success: false, error: 'Session introuvable' };
    else if (r.status >= 400) res = { success: false, error: 'Erreur ' + r.status };
    else {
      try {
        const c = JSON.parse(await r.text());
        const { apiKey: _a, nuagePass: _p, nuageUser: _u, ...safe } = c;
        res = { success: true, content: safe };
      } catch(e) { res = { success: false, error: e.message }; }
    }
  }
} else if (action === 'writeResult') {
  const { sessionId, studentId, data } = body;
  if (!sessionId || !studentId) { res = { success: false, error: 'sessionId et studentId requis' }; }
  else {
    const ss = studentId.replace(/[^a-zA-Z0-9]/g, '-').substring(0, 64);
    const fn = `result_${sessionId}_${ss}.json`;
    const d = typeof data === 'string' ? data : JSON.stringify(data, null, 2);
    let r = await hPut(nuageBase() + encodeURIComponent(fn), d);
    if ([404,405,409].includes(r.status)) { await hMkcol(nuageBase()); r = await hPut(nuageBase() + encodeURIComponent(fn), d); }
    if (r.status >= 400) { res = { success: false, error: 'Erreur ecriture ' + r.status }; }
    else { const m = await readManifest(); if (!m.includes(fn)) m.push(fn); await saveManifest(m); res = { success: true }; }
  }
} else if (action === 'readResult') {
  const { sessionId, studentId } = body;
  if (!sessionId || !studentId) { res = { success: false, error: 'sessionId et studentId requis' }; }
  else {
    const ss = studentId.replace(/[^a-zA-Z0-9]/g, '-').substring(0, 64);
    const fn = `result_${sessionId}_${ss}.json`;
    const r = await hGet(nuageBase() + encodeURIComponent(fn));
    if (r.status === 404) res = { success: false, error: 'Resultat introuvable' };
    else if (r.status >= 400) res = { success: false, error: 'Erreur ' + r.status };
    else { try { res = { success: true, content: JSON.parse(await r.text()) }; } catch(e) { res = { success: false, error: e.message }; } }
  }
} else if (action === 'albert') {
  const { messages, model, temperature = 0.3 } = body;
  if (!messages) { res = { error: 'messages requis' }; }
  else {
    const r = await fetch('https://albert.api.etalab.gouv.fr/v1/chat/completions', {
      method: 'POST',
      headers: { Authorization: `Bearer ${ALBERT_KEY}`, 'Content-Type': 'application/json' },
      body: JSON.stringify({ model: model || 'openai/gpt-oss-120b', messages, temperature, max_tokens: 3000 })
    });
    const d = await r.json();
    res = r.status >= 400 ? { error: 'Albert erreur ' + r.status, detail: d } : d;
  }
} else if (!PROF_SECRET || body.profSecret !== PROF_SECRET) {
  res = { success: false, error: 'Secret professeur invalide.' };
} else if (action === 'test') {
  let s = NUAGE_SERVER.replace('https://', '').replace('http://', '');
  if (s.endsWith('/')) s = s.slice(0, -1);
  const r = await fetch(`https://${s}/ocs/v1.php/cloud/user?format=json`, {
    headers: { Authorization: nuageAuth(), 'OCS-APIREQUEST': 'true' }
  });
  if (r.status === 401 || r.status === 403) res = { success: false, error: 'Credentials Nuage invalides - verifiez NUAGE_USER et NUAGE_PASS dans le noeud Code.' };
  else if (r.status !== 200) res = { success: false, error: 'Erreur OCS : ' + r.status };
  else { await hMkcol(nuageBase()); res = { success: true, user: NUAGE_USER, server: s }; }
} else if (action === 'listModels') {
  const r = await fetch('https://albert.api.etalab.gouv.fr/v1/models', { headers: { Authorization: `Bearer ${ALBERT_KEY}` } });
  const d = await r.json();
  res = r.status >= 400 ? { error: 'Albert erreur ' + r.status } : d;
} else if (action === 'list') {
  try { res = { success: true, files: (await readManifest()).map(n => ({ name: n })) }; }
  catch(e) { res = { success: false, error: e.message }; }
} else if (action === 'read') {
  const { filename } = body;
  if (!filename) { res = { success: false, error: 'filename requis' }; }
  else {
    const r = await hGet(nuageBase() + encodeURIComponent(filename));
    if (r.status === 404) res = { success: false, error: 'Fichier introuvable' };
    else if (r.status >= 400) res = { success: false, error: 'Erreur lecture ' + r.status };
    else { try { res = { success: true, content: JSON.parse(await r.text()) }; } catch(e) { res = { success: false, error: e.message }; } }
  }
} else if (action === 'write') {
  const { filename, content } = body;
  if (!filename) { res = { success: false, error: 'filename requis' }; }
  else {
    const d = typeof content === 'string' ? content : JSON.stringify(content, null, 2);
    let r = await hPut(nuageBase() + encodeURIComponent(filename), d);
    if ([404,405,409].includes(r.status)) { await hMkcol(nuageBase()); r = await hPut(nuageBase() + encodeURIComponent(filename), d); }
    if (r.status >= 400) { res = { success: false, error: 'Erreur ecriture ' + r.status }; }
    else { const m = await readManifest(); if (!m.includes(filename)) m.push(filename); await saveManifest(m); res = { success: true, action: 'write' }; }
  }
} else if (action === 'delete') {
  const { filename } = body;
  if (!filename) { res = { success: false, error: 'filename requis' }; }
  else {
    await hDel(nuageBase() + encodeURIComponent(filename));
    const m = await readManifest();
    await saveManifest(m.filter(n => n !== filename));
    res = { success: true, action: 'delete' };
  }
} else {
  res = { success: false, error: 'Action inconnue : ' + action };
}

return [{ json: res }];
